export async function registerStubs(
  lua: LuaEngine,
  flavor: "retail" | "classic" | "classic_era",
): Promise<void> {
  if (flavor === "retail") {
    await lua.doString(_retailLua);
  } else if (flavor === "classic") {
    // no classic delta yet — retail stubs cover all
    await lua.doString(_retailLua);
  } else if (flavor === "classic_era") {
    // no classic_era delta yet — retail stubs cover all
    await lua.doString(_retailLua);
  }
}

